sql:
SELECT zipcode, city, state
FROM zipcodes
WHERE median_age < 40 AND poverty_rate > 5;

SELECT zipcode, city, state 
FROM zipcodes 
WHERE median_age > 40 AND unemployment_rate < 3;

SELECT COUNT(zipcode) 
FROM zipcodes 
WHERE income > 75000;

external_knowledge:
- High average income refers to zipcodes with the highest median household income;
- Dense populations are those with a population density greater than 1000 people per square mile;
- The question seeks to identify the access date, username, median household income, and population density for these users.

sql:
SELECT COUNT(*)
FROM zipcodes
WHERE income > (SELECT AVG(income) FROM zipcodes);

SELECT AVG(income) AS avg_income
FROM zipcodes
WHERE median_age > 40;

SELECT unemployment_rate
FROM zipcodes
WHERE last_updated = (SELECT MAX(last_updated) FROM zipcodes);

SELECT city, state, SUM(population) AS TotalPopulation
FROM zipcodes
GROUP BY city, state;
